"use client";

import { useState, useEffect, useRef } from "react";
import {
    SparklesIcon,
    LightBulbIcon,
    EyeIcon,
    CheckBadgeIcon,
    PhotoIcon,
    PlusIcon,
    TrashIcon,
    ArrowUpIcon,
    ArrowDownIcon,
} from "@heroicons/react/24/outline";

/* ========== TYPES ========== */
type Stat = { value: string; label: string };
type ValueItem = { name: string; description: string };
type TeamImage = { url: string };

type HeroData = { title1: string; title2: string; description: string; stats: Stat[] };
type MissionData = { title: string; content: string };
type VisionData = { title: string; content: string };
type ValuesData = { sectionTitle: string; sectionDesc: string; items: ValueItem[] };
type TeamData = { title1: string; title2: string; description: string; images: TeamImage[]; statValue: string; statLabel: string };

/* ========== COMPONENT ========== */
export default function HakkimizdaEditorPage() {
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [saved, setSaved] = useState(false);

    // Section states
    const [hero, setHero] = useState<HeroData>({
        title1: "Geleceğinizi", title2: "Şansa Bırakmayın",
        description: "Türkiye'nin en köklü ve prestijli kamu sınavlarına hazırlık platformu. On binlerce başarı hikayesinin arkasındaki güç.",
        stats: [
            { value: "25K+", label: "Atanan Öğrenci" },
            { value: "150+", label: "Uzman Eğitmen" },
            { value: "%98", label: "Memnuniyet" },
        ],
    });

    const [mission, setMission] = useState<MissionData>({
        title: "Misyonumuz",
        content: "Her bir öğrencinin potansiyelini en üst düzeye çıkarmak için kişiselleştirilmiş eğitim modelini benimsiyoruz. Sadece bilgi yüklemek değil, bilgiyi kullanma becerisi kazandırarak kariyer yolculuklarında onlara rehberlik ediyoruz.",
    });

    const [vision, setVision] = useState<VisionData>({
        title: "Vizyonumuz",
        content: "Eğitim teknolojilerindeki son gelişmeleri geleneksel öğretim metotlarıyla harmanlayarak, global standartlarda bir eğitim platformu oluşturmak. Türkiye'nin her köşesine fırsat eşitliği ilkesiyle kaliteli eğitimi ulaştırmak.",
    });

    const [values, setValues] = useState<ValuesData>({
        sectionTitle: "Değerlerimiz",
        sectionDesc: "Bizi biz yapan ve her gün daha iyisi için çalışmamızı sağlayan temel prensiplerimiz.",
        items: [
            { name: "Uzmanlık", description: "Alanında otorite kabul edilen eğitmen kadrosu." },
            { name: "Kalite", description: "4K video çekimleri ve zengin içerik arşivi." },
            { name: "Disiplin", description: "Kişiye özel takip sistemi ve çalışma programları." },
            { name: "Güven", description: "Şeffaf süreç ve %98 öğrenci memnuniyeti." },
        ],
    });

    const [team, setTeam] = useState<TeamData>({
        title1: "Türkiye'nin En İyi",
        title2: "Eğitmen Kadrosu",
        description: "Sadece ders anlatan değil, sınav kazandıran bir kadro. Deneyim, bilgi ve rehberlik bir arada.",
        images: [],
        statValue: "150+",
        statLabel: "Uzman Eğitmen",
    });

    const teamImageRef = useRef<HTMLInputElement>(null);

    // Load from DB
    useEffect(() => {
        async function load() {
            try {
                const res = await fetch("/api/admin/page-content?page=hakkimizda");
                const data = await res.json();

                if (data.hero?.metadata) {
                    const m = data.hero.metadata;
                    setHero({
                        title1: m.title1 || hero.title1,
                        title2: m.title2 || hero.title2,
                        description: data.hero.content || hero.description,
                        stats: m.stats || hero.stats,
                    });
                }
                if (data.mission?.metadata) {
                    setMission({
                        title: data.mission.title || mission.title,
                        content: data.mission.content || mission.content,
                    });
                }
                if (data.vision?.metadata) {
                    setVision({
                        title: data.vision.title || vision.title,
                        content: data.vision.content || vision.content,
                    });
                }
                if (data.values?.metadata) {
                    const m = data.values.metadata;
                    setValues({
                        sectionTitle: data.values.title || values.sectionTitle,
                        sectionDesc: data.values.content || values.sectionDesc,
                        items: m.items || values.items,
                    });
                }
                if (data.team?.metadata) {
                    const m = data.team.metadata;
                    setTeam({
                        title1: m.title1 || team.title1,
                        title2: m.title2 || team.title2,
                        description: data.team.content || team.description,
                        images: m.images || team.images,
                        statValue: m.statValue || team.statValue,
                        statLabel: m.statLabel || team.statLabel,
                    });
                }
            } catch (e) {
                console.error("Yüklenemedi:", e);
            } finally {
                setLoading(false);
            }
        }
        load();
    }, []);

    // Save
    async function handleSave() {
        setSaving(true);
        try {
            await fetch("/api/admin/page-content", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    pageSlug: "hakkimizda",
                    sections: {
                        hero: {
                            title: hero.title1,
                            content: hero.description,
                            metadata: { title1: hero.title1, title2: hero.title2, stats: hero.stats },
                        },
                        mission: {
                            title: mission.title,
                            content: mission.content,
                            metadata: {},
                        },
                        vision: {
                            title: vision.title,
                            content: vision.content,
                            metadata: {},
                        },
                        values: {
                            title: values.sectionTitle,
                            content: values.sectionDesc,
                            metadata: { items: values.items },
                        },
                        team: {
                            title: team.title1,
                            content: team.description,
                            metadata: {
                                title1: team.title1,
                                title2: team.title2,
                                images: team.images,
                                statValue: team.statValue,
                                statLabel: team.statLabel,
                            },
                        },
                    },
                }),
            });
            setSaved(true);
            setTimeout(() => setSaved(false), 3000);
        } catch (e) {
            alert("Kayıt başarısız!");
        } finally {
            setSaving(false);
        }
    }

    // Image upload helper
    async function uploadImage(file: File): Promise<string | null> {
        const fd = new FormData();
        fd.append("file", file);
        const res = await fetch("/api/upload", { method: "POST", body: fd });
        const data = await res.json();
        return data.url || null;
    }

    async function handleTeamImageUpload(e: React.ChangeEvent<HTMLInputElement>) {
        const files = e.target.files;
        if (!files) return;
        for (let i = 0; i < files.length; i++) {
            const url = await uploadImage(files[i]);
            if (url) setTeam(prev => ({ ...prev, images: [...prev.images, { url }] }));
        }
        if (teamImageRef.current) teamImageRef.current.value = "";
    }

    // Styles
    const sectionCls = "bg-white rounded-xl border border-gray-200 p-6 space-y-5";
    const labelCls = "block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5";
    const inputCls = "w-full px-3 py-2.5 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition";
    const textareaCls = inputCls + " resize-none";

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-xl font-bold text-gray-900">Hakkımızda Sayfası</h1>
                    <p className="text-sm text-gray-400 mt-0.5">
                        Bu sayfadaki tüm metinleri, istatistikleri ve görselleri düzenleyebilirsiniz.
                    </p>
                </div>
                <button
                    onClick={handleSave}
                    disabled={saving}
                    className={`px-6 py-2.5 rounded-lg text-white text-sm font-bold transition ${saved
                        ? "bg-emerald-500"
                        : "bg-[#0B1221] hover:bg-[#1a2744]"
                        } disabled:opacity-50`}
                >
                    {saving ? "Kaydediliyor..." : saved ? "✓ Kaydedildi!" : "💾 Değişiklikleri Kaydet"}
                </button>
            </div>

            {/* ====================== HERO ====================== */}
            <div className={sectionCls}>
                <div className="flex items-center gap-2 pb-3 border-b border-gray-100">
                    <SparklesIcon className="w-5 h-5 text-yellow-500" />
                    <h2 className="text-sm font-bold text-gray-700">Hero Bölümü</h2>
                    <span className="text-[10px] text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">Sayfanın en üstündeki alan</span>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className={labelCls}>Başlık Satır 1</label>
                        <input className={inputCls} value={hero.title1} onChange={e => setHero({ ...hero, title1: e.target.value })} placeholder="Geleceğinizi" />
                    </div>
                    <div>
                        <label className={labelCls}>Başlık Satır 2 (Renkli)</label>
                        <input className={inputCls} value={hero.title2} onChange={e => setHero({ ...hero, title2: e.target.value })} placeholder="Şansa Bırakmayın" />
                    </div>
                </div>
                <div>
                    <label className={labelCls}>Açıklama</label>
                    <textarea className={textareaCls} rows={3} value={hero.description} onChange={e => setHero({ ...hero, description: e.target.value })} />
                </div>
                <div>
                    <label className={labelCls}>İstatistikler</label>
                    <div className="grid grid-cols-3 gap-3">
                        {hero.stats.map((s, i) => (
                            <div key={i} className="bg-gray-50 rounded-lg p-3 space-y-2">
                                <input className={inputCls + " text-center font-bold text-lg"} value={s.value} onChange={e => {
                                    const ns = [...hero.stats]; ns[i] = { ...ns[i], value: e.target.value }; setHero({ ...hero, stats: ns });
                                }} placeholder="25K+" />
                                <input className={inputCls + " text-center text-xs"} value={s.label} onChange={e => {
                                    const ns = [...hero.stats]; ns[i] = { ...ns[i], label: e.target.value }; setHero({ ...hero, stats: ns });
                                }} placeholder="Atanan Öğrenci" />
                                {hero.stats.length > 1 && (
                                    <button onClick={() => setHero({ ...hero, stats: hero.stats.filter((_, idx) => idx !== i) })}
                                        className="text-[10px] text-red-500 font-bold w-full hover:bg-red-50 py-1 rounded">Kaldır</button>
                                )}
                            </div>
                        ))}
                    </div>
                    <button onClick={() => setHero({ ...hero, stats: [...hero.stats, { value: "", label: "" }] })}
                        className="mt-2 text-xs text-blue-600 font-bold flex items-center gap-1 hover:underline">
                        <PlusIcon className="w-3 h-3" /> İstatistik Ekle
                    </button>
                </div>
            </div>

            {/* ====================== MİSYON & VİZYON ====================== */}
            <div className="grid grid-cols-2 gap-6">
                <div className={sectionCls}>
                    <div className="flex items-center gap-2 pb-3 border-b border-gray-100">
                        <LightBulbIcon className="w-5 h-5 text-red-500" />
                        <h2 className="text-sm font-bold text-gray-700">Misyon</h2>
                    </div>
                    <div>
                        <label className={labelCls}>Başlık</label>
                        <input className={inputCls} value={mission.title} onChange={e => setMission({ ...mission, title: e.target.value })} />
                    </div>
                    <div>
                        <label className={labelCls}>İçerik</label>
                        <textarea className={textareaCls} rows={5} value={mission.content} onChange={e => setMission({ ...mission, content: e.target.value })} />
                    </div>
                </div>

                <div className={sectionCls}>
                    <div className="flex items-center gap-2 pb-3 border-b border-gray-100">
                        <EyeIcon className="w-5 h-5 text-blue-500" />
                        <h2 className="text-sm font-bold text-gray-700">Vizyon</h2>
                    </div>
                    <div>
                        <label className={labelCls}>Başlık</label>
                        <input className={inputCls} value={vision.title} onChange={e => setVision({ ...vision, title: e.target.value })} />
                    </div>
                    <div>
                        <label className={labelCls}>İçerik</label>
                        <textarea className={textareaCls} rows={5} value={vision.content} onChange={e => setVision({ ...vision, content: e.target.value })} />
                    </div>
                </div>
            </div>

            {/* ====================== DEĞERLER ====================== */}
            <div className={sectionCls}>
                <div className="flex items-center gap-2 pb-3 border-b border-gray-100">
                    <CheckBadgeIcon className="w-5 h-5 text-green-500" />
                    <h2 className="text-sm font-bold text-gray-700">Değerlerimiz</h2>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className={labelCls}>Bölüm Başlığı</label>
                        <input className={inputCls} value={values.sectionTitle} onChange={e => setValues({ ...values, sectionTitle: e.target.value })} />
                    </div>
                    <div>
                        <label className={labelCls}>Bölüm Açıklaması</label>
                        <input className={inputCls} value={values.sectionDesc} onChange={e => setValues({ ...values, sectionDesc: e.target.value })} />
                    </div>
                </div>
                <div className="space-y-3">
                    <label className={labelCls}>Değer Kartları</label>
                    {values.items.map((item, i) => (
                        <div key={i} className="flex items-center gap-3 bg-gray-50 rounded-lg p-3">
                            <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-xs shrink-0">
                                {i + 1}
                            </div>
                            <input className={inputCls + " !w-40"} value={item.name} onChange={e => {
                                const ni = [...values.items]; ni[i] = { ...ni[i], name: e.target.value }; setValues({ ...values, items: ni });
                            }} placeholder="Değer adı" />
                            <input className={inputCls + " flex-1"} value={item.description} onChange={e => {
                                const ni = [...values.items]; ni[i] = { ...ni[i], description: e.target.value }; setValues({ ...values, items: ni });
                            }} placeholder="Açıklama" />
                            <button onClick={() => setValues({ ...values, items: values.items.filter((_, idx) => idx !== i) })}
                                className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg shrink-0">
                                <TrashIcon className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                    <button onClick={() => setValues({ ...values, items: [...values.items, { name: "", description: "" }] })}
                        className="text-xs text-blue-600 font-bold flex items-center gap-1 hover:underline">
                        <PlusIcon className="w-3 h-3" /> Yeni Değer Ekle
                    </button>
                </div>
            </div>

            {/* ====================== EKİP ====================== */}
            <div className={sectionCls}>
                <div className="flex items-center gap-2 pb-3 border-b border-gray-100">
                    <PhotoIcon className="w-5 h-5 text-purple-500" />
                    <h2 className="text-sm font-bold text-gray-700">Ekip Bölümü</h2>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className={labelCls}>Başlık Satır 1</label>
                        <input className={inputCls} value={team.title1} onChange={e => setTeam({ ...team, title1: e.target.value })} placeholder="Türkiye'nin En İyi" />
                    </div>
                    <div>
                        <label className={labelCls}>Başlık Satır 2 (Renkli)</label>
                        <input className={inputCls} value={team.title2} onChange={e => setTeam({ ...team, title2: e.target.value })} placeholder="Eğitmen Kadrosu" />
                    </div>
                </div>
                <div>
                    <label className={labelCls}>Açıklama</label>
                    <textarea className={textareaCls} rows={2} value={team.description} onChange={e => setTeam({ ...team, description: e.target.value })} />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className={labelCls}>İstatistik Değer</label>
                        <input className={inputCls} value={team.statValue} onChange={e => setTeam({ ...team, statValue: e.target.value })} placeholder="150+" />
                    </div>
                    <div>
                        <label className={labelCls}>İstatistik Etiket</label>
                        <input className={inputCls} value={team.statLabel} onChange={e => setTeam({ ...team, statLabel: e.target.value })} placeholder="Uzman Eğitmen" />
                    </div>
                </div>
                <div>
                    <label className={labelCls}>Ekip Görselleri (4 adet önerilir)</label>
                    <input type="file" ref={teamImageRef} onChange={handleTeamImageUpload} accept="image/*" multiple className="hidden" />
                    <div className="grid grid-cols-4 gap-3">
                        {team.images.map((img, i) => (
                            <div key={i} className="relative group h-32 rounded-xl overflow-hidden border border-gray-200">
                                <img src={img.url} alt="" className="w-full h-full object-cover" />
                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition flex items-center justify-center gap-1">
                                    <button onClick={() => setTeam({ ...team, images: team.images.filter((_, idx) => idx !== i) })}
                                        className="bg-red-500 text-white rounded-full p-1.5"><TrashIcon className="w-4 h-4" /></button>
                                </div>
                                <span className="absolute bottom-1 left-1 bg-black/60 text-white text-[9px] px-1.5 py-0.5 rounded font-bold">{i + 1}</span>
                            </div>
                        ))}
                        <button onClick={() => teamImageRef.current?.click()}
                            className="h-32 rounded-xl border-2 border-dashed border-gray-300 hover:border-purple-400 hover:bg-purple-50/50 transition flex flex-col items-center justify-center gap-1 text-gray-400">
                            <PhotoIcon className="w-6 h-6" />
                            <span className="text-[10px] font-bold">Görsel Ekle</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* Sticky Save Bar */}
            <div className="sticky bottom-4 bg-white/90 backdrop-blur-lg rounded-xl border border-gray-200 p-4 flex items-center justify-between shadow-lg">
                <p className="text-sm text-gray-500">
                    Değişikliklerinizi kaydetmeyi unutmayın.
                </p>
                <button
                    onClick={handleSave}
                    disabled={saving}
                    className={`px-8 py-2.5 rounded-lg text-white text-sm font-bold transition ${saved
                        ? "bg-emerald-500"
                        : "bg-[#0B1221] hover:bg-[#1a2744]"
                        } disabled:opacity-50`}
                >
                    {saving ? "Kaydediliyor..." : saved ? "✓ Kaydedildi!" : "💾 Kaydet"}
                </button>
            </div>
        </div>
    );
}
